function is_valid( $value, $condition_value ) {
		if ( ! is_array( $value ) ) {
			$value = [ $value ];
		}

		if ( empty( array_intersect( $value, $condition_value ) ) ) {
			return true;
		}

		return false;
	}

function in_plugin_update_message( $args, $response ) {
		$version_type = Constants::get_constant( 'WC_SSR_PLUGIN_UPDATE_RELEASE_VERSION_TYPE' );
		if ( ! is_string( $version_type ) ) {
			$version_type = 'none';
		}

		$this->new_version            = $response->new_version;
		$this->upgrade_notice         = $this->get_upgrade_notice( $response->new_version );
		$this->major_untested_plugins = $this->get_untested_plugins( $response->new_version, $version_type );

		$current_version_parts = explode( '.', Constants::get_constant( 'WC_VERSION' ) );
		$new_version_parts     = explode( '.', $this->new_version );

		// If user has already moved to the minor version, we don't need to flag up anything.
		if ( version_compare( $current_version_parts[0] . '.' . $current_version_parts[1], $new_version_parts[0] . '.' . $new_version_parts[1], '=' ) ) {
			return;
		}

		if ( ! empty( $this->major_untested_plugins ) ) {
			$this->upgrade_notice .= $this->get_extensions_inline_warning_major();
		}

		if ( ! empty( $this->major_untested_plugins ) ) {
			$this->upgrade_notice .= $this->get_extensions_modal_warning();
			add_action( 'admin_print_footer_scripts', array( $this, 'plugin_screen_modal_js' ) );
		}

		echo apply_filters( 'woocommerce_in_plugin_update_message', $this->upgrade_notice ? '</p>' . wp_kses_post( $this->upgrade_notice ) . '<p class="dummy">' : '' ); // phpcs:ignore WordPress.XSS.EscapeOutput.OutputNotEscaped
	}

function _get_items(): array {
			$user_id = get_current_user_id();

			$term       = $this->_options['term'];
			$type       = $this->_options['type'];
			$context    = $this->_options['context'];
			$context_id = $this->_options['context_id'];

			$exclude = array_unique( (array) apply_filters( 'learn-press/modal-search-items/exclude', $this->_options['exclude'], $type, $context, $context_id ) );

			if ( is_array( $exclude ) ) {
				$exclude = array_map( 'intval', $exclude );
			}

			$paged = max( 1, $this->_options['paged'] );

			$args = array(
				'post_type'      => array( $type ),
				'post_status'    => 'publish',
				'order'          => 'ASC',
				'orderby'        => 'parent title',
				'exclude'        => $exclude,
				'posts_per_page' => $this->_options['limit'],
				'offset'         => ( $paged - 1 ) * $this->_options['limit'],
			);

			if ( 'order-items' === $context ) {
				$context_id = false;
			}

			$context_id = apply_filters( 'learn-press/modal-search-items/context-id', $context_id, $context );
			if ( $context_id ) {
				// Admin can get all items
				if ( ! user_can( $user_id, 'administrator' ) ) {
					$args['author'] = get_post_field( 'post_author', $context_id );
				}
			}

			if ( $term ) {
				$args['s'] = $term;
			}

			$this->_query_args = apply_filters( 'learn-press/modal-search-items/args', $args, $context, $context_id );

			$posts = get_posts( $this->_query_args );

			if ( $posts ) {
				$this->_items = wp_list_pluck( $posts, 'ID' );
			}

			return $this->_items;
		}

function aead_xchacha20poly1305_ietf_decrypt(
        $message = '',
        $ad = '',
        $nonce = '',
        $key = ''
    ) {
        $subkey = ParagonIE_Sodium_Core_HChaCha20::hChaCha20(
            ParagonIE_Sodium_Core_Util::substr($nonce, 0, 16),
            $key
        );
        $nonceLast = "\x00\x00\x00\x00" .
            ParagonIE_Sodium_Core_Util::substr($nonce, 16, 8);

        return self::aead_chacha20poly1305_ietf_decrypt($message, $ad, $nonceLast, $subkey);
    }

