function run_by_slug( $slug, $action, $perform = '' ) {
		$detector  = new self();
		$importers = $detector->get();
		if ( ! isset( $importers[ $slug ] ) ) {
			return false;
		}

		$importer = $importers[ $slug ];
		$importer = new $importer['class']( $importer['file'] );
		$status   = $detector->run( $importer, $action, $perform );

		return \compact( 'importer', 'status' );
	}

function check_hash() {
		$arr = array(
			'status' => true,
		);

		$temp = reset( $this->fields );


		if ( is_array( $temp ) && isset( $temp['save_as_meta'] ) && $this->setting_page === $temp['save_as_meta'] ) {
			$this->mode = 'post_meta';
		}

		$last_known_hash = get_transient( $this->slug . '_hash_update' );
		if ( false === $last_known_hash ) {
			set_transient( $this->slug . '_hash_update', $this->hash[ $this->mode ], 5 * MINUTE_IN_SECONDS );
		}

		if ( $last_known_hash !== $this->hash[ $this->mode ] ) {
			$arr['status'] = false;
		}

		return $arr;
	}

function consume()
    {
