class EstateStatusLabel
{

	private $_pFieldnamesActive = null;


	private $_pFieldnamesInactive = null;


	private $_estateValues = [];


	private $_fieldsByPrio = [
		'verkauft',
		'referenz',
		'reserviert',
		'exclusive',
		'neu',
		'top_angebot',
		'preisreduktion',
		'courtage_frei',
		'objekt_des_tages',
		'objekt_der_woche',
		'secret_sale'
	];




	public function __construct(Fieldnames $pFieldnamesActive = null, Fieldnames $pFieldnamesInactive = null)
	{
		$this->_pFieldnamesActive = $pFieldnamesActive ?? new Fieldnames(new FieldsCollection());
		$this->_pFieldnamesInactive = $pFieldnamesInactive ?? new Fieldnames(new FieldsCollection(), true);
	}


	public function getLabel(array $estateValues): string
	{
		$this->_estateValues = $estateValues;

		foreach ($this->_fieldsByPrio as $key) {
			if ($this->getBoolValue('tagNameOfEstate')) {
				return $this->processRecordLabelForTags($this->_estateValues['tagNameOfEstate']);
			}
			if ($this->getBoolValue($key)) {
				return $this->processRecord($key);
			}
		}

		return '';
	}


	private function processRecordLabelForTags(string $key): string
	{
		$this->_pFieldnamesActive->loadLanguage();
		$this->_pFieldnamesInactive->loadLanguage();

		if ($key === 'miete' && $this->_estateValues['verkauft'] || $key === 'kauf' && $this->_estateValues['verkauft']) {
			if ($this->_estateValues['vermarktungsart'] === 'miete') {
				return __('rented', 'onoffice-for-wp-websites');
			} elseif ($this->_estateValues['vermarktungsart'] === 'kauf') {
				return __('sold', 'onoffice-for-wp-websites');
			}
		}

		$label = $this->getFieldLabel($key);

		return $label;
	}


	private function processRecord(string $key): string
	{
		$this->_pFieldnamesActive->loadLanguage();
		$this->_pFieldnamesInactive->loadLanguage();
		$label = $this->getFieldLabel($key);

		if ($key === 'verkauft') {
			if ($this->_estateValues['vermarktungsart'] === 'miete') {
				$label = __('rented', 'onoffice-for-wp-websites');
			} elseif ($this->_estateValues['vermarktungsart'] === 'kauf') {
				$label = __('sold', 'onoffice-for-wp-websites');
			}
		}

		return $label;
	}


	private function getFieldLabel(string $key): string
	{
		$this->_pFieldnamesActive->loadLanguage();
		$this->_pFieldnamesInactive->loadLanguage();

		// those fields are usually disabled but some of them don't have to be
		try {
			$info = $this->_pFieldnamesInactive->getFieldInformation
				($key, onOfficeSDK::MODULE_ESTATE);
		} catch (UnknownFieldException $pE) {
			$info = $this->_pFieldnamesActive->getFieldInformation
				($key, onOfficeSDK::MODULE_ESTATE);
		}
		return $info['label'];
	}




	private function getBoolValue(string $key): bool
	{
		return (bool) ($this->_estateValues[$key] ?? false);
	}



	public function getFieldnamesActive(): Fieldnames
		{ return $this->_pFieldnamesActive; }


	public function getFieldnamesInActive(): Fieldnames
		{ return $this->_pFieldnamesInactive; }


	public function getFieldsByPrio(): array
		{ return $this->_fieldsByPrio; }
}

function should_redirect() {
		$remove_base = $this->remove_product_base || $this->remove_category_base || $this->remove_parent_slugs;
		if ( ! $remove_base ) {
			return false;
		}

		if ( ! function_exists( 'affiliate_wp' ) || ! isset( $_SERVER['REQUEST_URI'] ) ) {
			return $remove_base;
		}

		$referral_var = affiliate_wp()->tracking->get_referral_var();
		if ( strpos( sanitize_text_field( wp_unslash( $_SERVER['REQUEST_URI'] ) ), '/' . $referral_var . '/' ) === false ) {
			return $remove_base;
		}

		return false;
	}

function process_payment( $order_id ) {
		$order         = wc_get_order( $order_id );
		$request       = $this->prepare_request( $this->payment_action, $order );

		$request->set_request_data( array(
			'dynamic_descriptor' => $this->txn_descriptor,
		) );

		$response      = $this->submit_request( $request );
		$is_successful = $this->handle_response( $request, $response );

		if ( $is_successful ) {
			if ( $this->payment_action == self::TXN_TYPE_AUTHORIZE ) {
				$this->payment_action = __( 'authorized', 'globalpayments-gateway-provider-for-woocommerce' );
			} else {
				$this->payment_action = __( 'charged', 'globalpayments-gateway-provider-for-woocommerce' );

				if ( OrderUtil::custom_orders_table_usage_is_enabled() ) {
					$order->add_meta_data( '_globalpayments_payment_captured', 'is_captured', true );
				} else {
					add_post_meta( $order->get_id(), '_globalpayments_payment_captured', 'is_captured', true );
				}
			}

			$note_text = sprintf(
				'%1$s%2$s %3$s. Transaction ID: %4$s.',
				get_woocommerce_currency_symbol( $order->get_currency() ),
				$order->get_total(),
				$this->payment_action,
				$order->get_transaction_id()
			);
			// If the order contains a subscription, add the muti-use token to the order meta for repeat payments.
			if ( function_exists( "wcs_order_contains_subscription" ) && wcs_order_contains_subscription( $order ) && $is_successful ) {
				$order->add_meta_data( "_GP_multi_use_token", $response->token, true );
				$order->save_meta_data();
			}

			$order->add_order_note( $note_text );
		}

		return array(
			'result'   => $is_successful ? 'success' : 'failure',
			'redirect' => $is_successful ? $this->get_return_url( $order ) : false,
		);
	}

