function management_page_load() {
		require_once WP_POLLDADDY__POLLDADDY_CLIENT_PATH;

		$is_POST = 'post' == strtolower( $_SERVER['REQUEST_METHOD'] );
		wp_reset_vars( array( 'action', 'page' ) );
		global $action, $page;

		$this->set_api_user_code();

		if ( 'polls' === $page || 'crowdsignal-settings' === $page ) {
			switch ( $action ) {
			case 'update-options' :
				if ( !$is_POST )
					return;

				if ( $this->is_admin ) {
					check_admin_referer( 'polldaddy-account' );

					$polldaddy = $this->get_client( WP_POLLDADDY__PARTNERGUID, $this->user_code );
					$polldaddy->reset();

					$polldaddy_sync_account      = 0;
					$polldaddy_multiple_accounts = 0;
					$polldaddy_load_poll_inline  = 0;

					if ( isset( $_POST['polldaddy-sync-account'] ) )
						$polldaddy_sync_account = (int) $_POST['polldaddy-sync-account'];

					if ( $polldaddy_sync_account > 0 ) {
						$this->log( 'management_page_load: sync usercode' );
						$this->rating_user_code = '';
						update_option( 'pd-rating-usercode', '' );
						$this->set_api_user_code();
					}

					if ( isset( $_POST['polldaddy-multiple-accounts'] ) )
						$polldaddy_multiple_accounts = (int) $_POST['polldaddy-multiple-accounts'];

					if ( isset( $_POST['polldaddy-load-poll-inline'] ) )
						$polldaddy_load_poll_inline = (int) $_POST['polldaddy-load-poll-inline'];

					$partner = array( 'role' => $polldaddy_multiple_accounts );
					$polldaddy->update_partner_account( $partner );
					update_option( 'polldaddy_multiple_accounts', $polldaddy_multiple_accounts );
					update_option( 'polldaddy_load_poll_inline', $polldaddy_load_poll_inline );
				}
				break;
			} //end switch
		}

		global $parent_file, $submenu_file, $typenow;

		//need to set this to make sure that menus behave properly
		if ( in_array( $action, array( 'options', 'update-rating' ) ) ) {
			$parent_file  = 'admin.php';
			$submenu_file = $page.'&action=options';
		} else {
			add_filter( 'admin_title', array( &$this, 'admin_title' ) );
			$submenu_file = $page;
		}

		parent::management_page_load();
	}

function update_list( array $updated_list = [] ) {

		$return_list = false;

		try {

			$list = new ContactList();

			$list->id       = isset( $updated_list['id'] ) ? esc_attr( $updated_list['id'] ) : '';
			$list->name     = isset( $updated_list['name'] ) ? esc_attr( $updated_list['name'] ) : '';
			$list->favorite = isset( $updated_list['favorite'] ) ? esc_attr( $updated_list['favorite'] ) : false;


			$list->status = apply_filters( 'constant_contact_list_status', 'HIDDEN' );

			$return_list = $this->cc()->update_list( (array) $list );
			if ( array_key_exists( 'error_key', $return_list ) && 'unauthorized' === $return_list['error_key'] ) {
				$this->refresh_token();
				$return_list = $this->cc()->update_list( $list );
			}
		} catch ( CtctException $ex ) {
			add_filter( 'constant_contact_force_logging', '__return_true' );
			$extra        = constant_contact_location_and_line( __METHOD__, __LINE__ );
			$errors       = $ex->getErrors();
			$our_errors[] = $extra . ' - ' . $errors[0]->error_key . ' - ' . $errors[0]->error_message;
			$this->log_errors( $our_errors );
			constant_contact_forms_maybe_set_exception_notice( $ex );
		} catch ( Exception $ex ) {
			$error                = new stdClass();
			$error->error_key     = get_class( $ex );
			$error->error_message = $ex->getMessage();

			add_filter( 'constant_contact_force_logging', '__return_true' );
			constant_contact_forms_maybe_set_exception_notice( $ex );

			$extra        = constant_contact_location_and_line( __METHOD__, __LINE__ );
			$our_errors[] = $extra . ' - ' . $error->error_key . ' - ' . $error->error_message;
			$this->log_errors( $our_errors );
		}

		return $return_list;
	}

function current_screen( $screen ) {
		// 一覧画面
		if ( 'edit-' . SCF_Config::NAME === $screen->id ) {
			return;
		}

		// 新規作成・編集画面
		if ( SCF_Config::NAME === $screen->id ) {
			require_once plugin_dir_path( __FILE__ ) . 'classes/controller/class.settings.php';
			new Smart_Custom_Fields_Controller_Settings();
			return;
		}

		// その他の新規作成・編集画面
		if ( in_array( $screen->id, get_post_types(), true ) ) {
			$post_id = $this->get_post_id_in_admin();
			if ( SCF::get_settings( SCF::generate_post_object( $post_id, $screen->id ) ) ) {
				require_once plugin_dir_path( __FILE__ ) . 'classes/controller/class.controller-base.php';
				require_once plugin_dir_path( __FILE__ ) . 'classes/controller/class.editor.php';
				new Smart_Custom_Fields_Revisions();
				new Smart_Custom_Fields_Controller_Editor();
			}
			return;
		}

		// プロフィール編集画面
		if ( in_array( $screen->id, array( 'profile', 'user-edit' ), true ) ) {
			$user_id = $this->get_user_id_in_admin();
			if ( SCF::get_settings( get_userdata( $user_id ) ) ) {
				require_once plugin_dir_path( __FILE__ ) . 'classes/controller/class.controller-base.php';
				require_once plugin_dir_path( __FILE__ ) . 'classes/controller/class.profile.php';
				new Smart_Custom_Fields_Controller_Profile();
			}
			return;
		}

		// タグ、カテゴリー、タクソノミー
		if ( $screen->taxonomy ) {
			$term_id = $this->get_term_id_in_admin();
			if ( $term_id ) {
				$term = get_term( $term_id, $screen->taxonomy );
				if ( SCF::get_settings( $term ) ) {
					require_once plugin_dir_path( __FILE__ ) . 'classes/controller/class.controller-base.php';
					require_once plugin_dir_path( __FILE__ ) . 'classes/controller/class.taxonomy.php';
					new Smart_Custom_Fields_Controller_Taxonomy();
				}
			}
			return;
		}

		// オプションページ
		$menu_slug     = preg_replace( '/^toplevel_page_(.+)$/', '$1', $screen->id );
		$options_pages = SCF::get_options_pages();
		if ( array_key_exists( $menu_slug, $options_pages ) ) {
			$option = SCF::generate_option_object( $menu_slug );
			if ( SCF::get_settings( $option ) ) {
				require_once plugin_dir_path( __FILE__ ) . 'classes/controller/class.controller-base.php';
				require_once plugin_dir_path( __FILE__ ) . 'classes/controller/class.option.php';
				new Smart_Custom_Fields_Controller_Option();
			}
		}
	}

