function escape_css( string $ident ): string {
		$length          = strlen( $ident );
		$result          = '';
		$first_code_unit = $length > 0 ? ord( $ident[0] ) : 0;

		for ( $i = 0; $i < $length; $i++ ) {
			$code_unit = ord( $ident[ $i ] );

			// If the character is NULL (U+0000), then the REPLACEMENT CHARACTER (U+FFFD).
			if ( 0x0000 === $code_unit ) {
				$result .= "\u{FFFD}";
				continue;
			}

			if (
				// If the character is in the range [\1-\1f] (U+0001 to U+001F) or is U+007F...
				$code_unit <= 0x001F || 0x007F === $code_unit ||
				// If the character is the first character and is in the range [0-9] (U+0030 to U+0039)...
				( 0 === $i && $code_unit >= 0x0030 && $code_unit <= 0x0039 ) ||
				// If the character is the second character and is in the range [0-9] (U+0030 to U+0039) and the first character is a `-` (U+002D)...
				( 1 === $i && $code_unit >= 0x0030 && $code_unit <= 0x0039 && 0x002D === $first_code_unit )
			) {
				$result .= '\\' . dechex( $code_unit ) . ' ';
				continue;
			}

			// If the character is the first character and is a `-` (U+002D), and there is no second character...
			if (
				0 === $i &&
				1 === $length &&
				0x002D === $code_unit
			) {
				$result .= '\\' . $ident[ $i ];
				continue;
			}

			// If the character is not handled by one of the above rules and is
			// greater than or equal to U+0080, is `-` (U+002D) or `_` (U+005F), or
			// is in one of the ranges [0-9] (U+0030 to U+0039), [A-Z] (U+0041 to
			// U+005A), or [a-z] (U+0061 to U+007A)...
			if (
				$code_unit >= 0x0080 ||
				0x002D === $code_unit ||
				0x005F === $code_unit ||
				( $code_unit >= 0x0030 && $code_unit <= 0x0039 ) ||
				( $code_unit >= 0x0041 && $code_unit <= 0x005A ) ||
				( $code_unit >= 0x0061 && $code_unit <= 0x007A )
			) {
				$result .= $ident[ $i ];
				continue;
			}

			// Otherwise, the escaped character.
			$result .= '\\' . $ident[ $i ];
		}
		return $result;
	}

function get_search_analytics( $args = [] ) {
		$dates = Base::get_dates();

		$start_date = isset( $args['start_date'] ) ? $args['start_date'] : $dates['start_date'];
		$end_date   = isset( $args['end_date'] ) ? $args['end_date'] : $dates['end_date'];
		$dimensions = isset( $args['dimensions'] ) ? $args['dimensions'] : 'date';
		$row_limit  = isset( $args['row_limit'] ) ? $args['row_limit'] : Api::get()->get_row_limit();

		$params = [
			'startDate'  => $start_date,
			'endDate'    => $end_date,
			'rowLimit'   => $row_limit,
			'dimensions' => \is_array( $dimensions ) ? $dimensions : [ $dimensions ],
		];

		$stored  = get_option(
			'rank_math_google_analytic_profile',
			[
				'country'             => '',
				'profile'             => '',
				'enable_index_status' => true,
			]
		);
		$country = isset( $args['country'] ) ? $args['country'] : $stored['country'];
		$profile = isset( $args['profile'] ) ? $args['profile'] : $stored['profile'];

		if ( 'all' !== $country ) {
			$params['dimensionFilterGroups'] = [
				[
					'filters' => [
						[
							'dimension'  => 'country',
							'operator'   => 'equals',
							'expression' => $country,
						],
					],
				],
			];
		}

		if ( empty( $profile ) ) {
			$profile = trailingslashit( strtolower( home_url() ) );
		}

		$workflow = 'console';
		$this->set_workflow( $workflow );
		$response = $this->http_post(
			'https://www.googleapis.com/webmasters/v3/sites/' . rawurlencode( $profile ) . '/searchAnalytics/query',
			$params
		);

		$this->log_failed_request( $response, $workflow, $start_date, func_get_args() );

		if ( ! $this->is_success() ) {
			return new WP_Error( 'request_failed', __( 'The Google Search Console request failed.', 'rank-math' ) );
		}

		if ( ! isset( $response['rows'] ) ) {
			return false;
		}

		return $response['rows'];
