			$message .= sprintf(
			/* translators: Placeholders: %1$s - plugin name, %2$s - <a> tag, %3$s - </a> tag, %4$s - <a> tag, %5$s - </a> tag */
				__( 'Are you having a great experience with %1$s so far? Please consider %2$sleaving a review%3$s! If things aren\'t going quite as expected, we\'re happy to help -- please %4$sreach out to our support team%5$s.', 'woocommerce-square' ),
				'<strong>' . esc_html( $this->get_plugin()->get_plugin_name() ) . '</strong>',
				'<a href="' . esc_url( $this->get_plugin()->get_reviews_url() ) . '">',
				'</a>',
				'<a href="' . esc_url( $this->get_plugin()->get_support_url() ) . '">',
				'</a>'
			);
		}

		return $message;
	}

function tryCalculation(string $name, int $start): ?CalculationExpression
    {
        assert($this->scanner->peekChar() === '(');

        switch ($name) {
            case 'calc':
                $arguments = $this->calculationArguments(1);

                return new CalculationExpression($name, $arguments, $this->scanner->spanFrom($start));

            case 'min':
            case 'max':
                // min() and max() are parsed as calculations if possible, and otherwise
                // are parsed as normal Sass functions.
                $beforeArguments = $this->scanner->getPosition();

                try {
                    $arguments = $this->calculationArguments();
                } catch (FormatException $e) {
                    $this->scanner->setPosition($beforeArguments);

                    return null;
                }

                return new CalculationExpression($name, $arguments, $this->scanner->spanFrom($start));

            case 'clamp':
                $arguments = $this->calculationArguments(3);

                return new CalculationExpression($name, $arguments, $this->scanner->spanFrom($start));

            default:
                return null;
        }
    }

