function admin_enforce_single_gateway( $settings ) {
		if ( ! wc_string_to_bool( $settings['enabled'] ) ) {
			return $settings;
		}

		$available_gateways = WC()->payment_gateways->get_available_payment_gateways();
		if ( isset( $available_gateways[ $this->id ] ) ) {
			return $settings;
		}
		foreach ( $available_gateways as $gateway ) {
			if ( $gateway instanceof AbstractGateway ) {
				$settings['enabled'] = 'no';
				add_action( 'woocommerce_sections_checkout', function () use ( $gateway ) {
						echo '<div id="message" class="error inline"><p><strong>' .
						sprintf(
                            /* translators: %s: You can enable only one GlobalPayments gateway at a time */
							esc_html__( 'You can enable only one GlobalPayments gateway at a time. Please disable %s first!', 'globalpayments-gateway-provider-for-woocommerce' ),
							esc_html($gateway->method_title)
						) . '</strong></p></div>';
					}
				);

				return $settings;
			}
		}

		return $settings;
	}

function wp_set_post_categories( $post_id = 0, $post_categories = array(), $append = false ) {
	$post_id     = (int) $post_id;
	$post_type   = get_post_type( $post_id );
	$post_status = get_post_status( $post_id );

	// If $post_categories isn't already an array, make it one.
	$post_categories = (array) $post_categories;

	if ( empty( $post_categories ) ) {

		$default_category_post_types = apply_filters( 'default_category_post_types', array() );

		// Regular posts always require a default category.
		$default_category_post_types = array_merge( $default_category_post_types, array( 'post' ) );

		if ( in_array( $post_type, $default_category_post_types, true )
			&& is_object_in_taxonomy( $post_type, 'category' )
			&& 'auto-draft' !== $post_status
		) {
			$post_categories = array( get_option( 'default_category' ) );
			$append          = false;
		} else {
			$post_categories = array();
		}
	} elseif ( 1 === count( $post_categories ) && '' === reset( $post_categories ) ) {
		return true;
	}

	return wp_set_post_terms( $post_id, $post_categories, 'category', $append );
}

function wp_super_cache_jetpack_cookie_check( $cache_key ) {
	if ( isset ( $_COOKIE['akm_mobile'] ) ) {
		if ( $_COOKIE['akm_mobile'] == 'true' ) {
			return 'mobile';
		} elseif ( $_COOKIE['akm_mobile'] == 'false' ) {
			return 'normal';
		}
	}

	if ( ! class_exists( 'Automattic\WPSC\Device_Detection' ) ) {
		return 'normal';
	}

	if ( \Automattic\WPSC\Device_Detection::is_phone() ) {
		return 'mobile';
	} else {
		return 'normal';
	}
}

