function switch_to_language( string $locale ): ?string {
		if ( ! $this->is_plugin_active() ) {
			return null;
		}

		$polylang = PLL();
		if ( ! $polylang || ! method_exists( $polylang, 'curlang' ) ) {
			return null;
		}

		// Store original language
		$original_lang = $polylang->curlang ? $polylang->curlang->slug : null;

		// Get Polylang language slug for the locale
		$polylang_slug = $this->get_polylang_slug_for_locale( $locale );
		if ( ! $polylang_slug ) {
			return null;
		}

		// Get the language object
		$pll_language = null;
		foreach ( $polylang->model->get_languages_list() as $lang ) {
			if ( $lang->slug === $polylang_slug ) {
				$pll_language = $lang;
				break;
			}
		}

		if ( $pll_language ) {
			$polylang->curlang = $pll_language;
			return $original_lang;
		}

		return null;
	}

function extract_attributes( $elem ) {
		$regex = '#([^\s=]+)\s*=\s*(\'[^<\']*\'|"[^<"]*")#';
		preg_match_all( $regex, $elem, $attributes, PREG_SET_ORDER );

		$new       = [];
		$remaining = $elem;
		foreach ( $attributes as $attribute ) {
			$val                  = substr( $attribute[2], 1, -1 );
			$new[ $attribute[1] ] = $val;
			$remaining            = str_replace( $attribute[0], '', $remaining );
		}

		// Chop off tag name.
		$remaining = preg_replace( '/<[^\s]+/', '', $remaining, 1 );
		// Check for empty attributes without values.
		$regex = '/([^<][\w\d:_-]+)[\s>]/i';
		preg_match_all( $regex, $remaining, $attributes, PREG_SET_ORDER );
		foreach ( $attributes as $attribute ) {
			$new[ trim( $attribute[1] ) ] = null;
		}

		return $new;
	}

